# ===== woos 틱 수집기 배포 (VM 터미널에 통째로 붙여넣기) =====
# 1) 코드 파일 생성
echo '' | base64 -d > ~/woos_tick_collector.py
python3 -c "import ast; ast.parse(open('/home/neosiwon/woos_tick_collector.py').read()); print('문법 OK')"

# 2) 의존성 설치
pip install websocket-client --break-system-packages 2>&1 | tail -1

# 3) systemd 서비스 등록
sudo tee /etc/systemd/system/woos-tick-collector.service > /dev/null << 'SVC'
[Unit]
Description=woos tick collector (Upbit trade ticks)
After=network-online.target
Wants=network-online.target

[Service]
Type=simple
User=neosiwon
WorkingDirectory=/home/neosiwon
ExecStart=/usr/bin/python3 /home/neosiwon/woos_tick_collector.py
Restart=always
RestartSec=5
StandardOutput=journal
StandardError=journal

[Install]
WantedBy=multi-user.target
SVC

# 4) 시작
sudo systemctl daemon-reload
sudo systemctl enable woos-tick-collector
sudo systemctl restart woos-tick-collector
sleep 3
sudo systemctl status woos-tick-collector --no-pager | head -8
echo "===== 5초 후 로그 확인 ====="
sleep 5
journalctl -u woos-tick-collector -n 15 --no-pager
